-- ============================================================================
-- AFU JOB LISTINGS: Full Update Script
-- Updates all 33 job listings with org-chart ordering and rich descriptions
-- Run in Supabase SQL Editor
-- ============================================================================

-- Step 1: Add missing columns that the frontend expects but the DB schema lacks
ALTER TABLE job_listings ADD COLUMN IF NOT EXISTS requirements TEXT;
ALTER TABLE job_listings ADD COLUMN IF NOT EXISTS skills TEXT[] DEFAULT '{}';
ALTER TABLE job_listings ADD COLUMN IF NOT EXISTS experience_years INTEGER DEFAULT 0;
ALTER TABLE job_listings ADD COLUMN IF NOT EXISTS education TEXT;

