-- 20. Country Director — Zimbabwe (Pilot) (position 14)
UPDATE job_listings SET
  created_at = '2026-03-25T00:14:00Z',
  description = E'Zimbabwe is AFU\u2019s pilot country. Everything we build here becomes the template for 9 more countries. You\u2019ll launch the Watson & Fine blueberry export program, onboard the first cohort of smallholder farmers, and prove that the AFU model works. This is the most important Country Director role in the company.\n\nResponsibilities:\n\u2022 Own the Zimbabwe P&L \u2014 revenue, costs, farmer growth, loan performance\n\u2022 Launch the Watson & Fine blueberry export program (25ha commercial operation)\n\u2022 Onboard the first 5,000 smallholder farmers in Year 1\n\u2022 Build and manage the Zimbabwe team (Operations, Finance, Agronomy, Commercial, Insurance, Compliance)\n\u2022 Establish relationships with Zimbabwean government (Agriculture Ministry, RBZ, ZIMRA)\n\u2022 Register and operationalize the Zimbabwe farmer cooperative (51% farmer-owned)\n\u2022 Manage local banking relationships and EcoCash mobile money integration\n\u2022 Ensure all operations comply with Zimbabwean regulations\n\u2022 Coordinate with HQ on platform localization (Shona language, local content)\n\u2022 Build the proof-of-concept that unlocks the next $450M+ in deployment',
  requirements = E'Requirements:\n\u2022 7+ years in agricultural business, development, or fintech in Zimbabwe\n\u2022 Deep understanding of Zimbabwean farming landscape (commercial and smallholder)\n\u2022 Strong relationships with Zimbabwean government and agricultural institutions\n\u2022 Experience managing teams of 20+ people\n\u2022 Understanding of EcoCash and local payment systems\n\u2022 Knowledge of Zimbabwean cooperative and agricultural law\n\u2022 Track record of delivering results in challenging environments\n\u2022 Fluency in English and Shona\n\nNice to Have:\n\u2022 Experience with blueberry or horticultural operations\n\u2022 Knowledge of tobacco, maize, or soya value chains in Zimbabwe\n\u2022 Existing relationships with TIMB, GMB, or other statutory bodies\n\u2022 Experience with agricultural lending or microfinance in Zimbabwe',
  skills = ARRAY['Country leadership', 'Cooperative management', 'Agricultural development', 'Regulatory affairs'],
  experience_years = 7,
  education = E'Business, Agriculture, or related degree'
WHERE title = 'Country Director — Zimbabwe (Pilot)';

-- 21. Country Director — Uganda (position 13)
UPDATE job_listings SET
  created_at = '2026-03-25T00:13:00Z',
  description = E'Launch Uganda operations with 19,000 pre-identified farmers. Build the team, register the cooperative, establish MTN MoMo/Airtel Money operations, and scale coffee, maize, and banana value chains. Uganda is AFU\u2019s second market and a critical proof point for East African expansion.\n\nResponsibilities:\n\u2022 Own the Uganda P&L \u2014 revenue, costs, farmer growth, loan performance\n\u2022 Onboard 19,000 pre-identified farmers in Year 1\n\u2022 Register and operationalize the Uganda farmer cooperative (51% farmer-owned)\n\u2022 Establish MTN MoMo and Airtel Money integration for loan disbursements and collections\n\u2022 Build and manage the Uganda country team (Operations, Finance, Agronomy, Commercial)\n\u2022 Develop coffee, maize, and banana value chains with local and export buyers\n\u2022 Build relationships with Ugandan government (MAAIF, Bank of Uganda, URA)\n\u2022 Coordinate with Regional Director \u2014 East Africa on cross-border trade opportunities\n\u2022 Ensure all operations comply with Ugandan regulations and cooperative law\n\u2022 Coordinate with HQ on platform localization (Luganda language, local content)',
  requirements = E'Requirements:\n\u2022 7+ years in agricultural business, development, or fintech in Uganda\n\u2022 Deep understanding of Ugandan farming landscape (smallholder and commercial)\n\u2022 Strong relationships with Ugandan government and agricultural institutions\n\u2022 Experience managing teams of 15+ people\n\u2022 Understanding of MTN MoMo, Airtel Money, and local payment systems\n\u2022 Knowledge of Ugandan cooperative and agricultural law\n\u2022 Track record of delivering results in East African markets\n\u2022 Fluency in English and Luganda\n\nNice to Have:\n\u2022 Experience with coffee, maize, or banana value chains in Uganda\n\u2022 Existing relationships with UCDA, NAADS, or other agricultural bodies\n\u2022 Experience with agricultural lending or microfinance in Uganda\n\u2022 Knowledge of EAC cross-border trade frameworks',
  skills = ARRAY['Country operations', 'Cooperative formation', 'Mobile money', 'Coffee/maize value chains'],
  experience_years = 7,
  education = E'Business, Agriculture, or related degree'
